    calculateDrishti: {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        requestBody?: {
            content: {
                "application/json": {
                    /**
                     * @description Date in YYYY-MM-DD format. Planetary positions are calculated for this date to determine mutual aspects (drishti).
                     * @example 2026-02-03
                     */
                    date: string;
                    /**
                     * @description Time in HH:MM:SS format (24-hour). Exact time affects fast-moving planets (Moon, Mercury) and aspect orbs.
                     * @example 12:00:00
                     */
                    time: string;
                    /**
                     * @description Observer latitude in decimal degrees. Used for Lagna calculation which affects house-based aspect analysis.
                     * @example 17.385044
                     */
                    latitude: number;
                    /**
                     * @description Observer longitude in decimal degrees. Affects local sidereal time for positional calculations.
                     * @example 78.486671
                     */
                    longitude: number;
                    /**
                     * @description Timezone offset from UTC in hours. Defaults to 5.5 (IST).
                     * @default 5.5
                     * @example 5.5
                     */
                    timezone?: number;
                    /**
                     * @description Coordinate system for longitude output. "sidereal" (Nirayana) uses Lahiri ayanamsa - standard for Vedic astrology. "tropical" (Sayana) uses raw ecliptic longitude matching Western astrology. Defaults to "sidereal".
                     * @default sidereal
                     * @example sidereal
                     * @enum {string}
                     */
                    coordinateSystem?: "sidereal" | "tropical";
                };
            };
        };
        responses: {
            /** @description Aspects calculated successfully */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        /** @description UTC datetime used for aspect calculation (ISO 8601). */
                        datetime: string;
                        /** @description Sidereal positions of all 9 planets at the given time. */
                        planets: {
                            /**
                             * @description Planet name (Sun through Ketu, all 9 Vedic grahas).
                             * @example Mars
                             */
                            name: string;
                            /**
                             * @description Sidereal longitude in degrees (0-360).
                             * @example 285.67
                             */
                            longitude: number;
                            /**
                             * @description Vedic zodiac sign (rashi) the planet occupies.
                             * @example Capricorn
                             */
                            sign: string;
                        }[];
                        /** @description Complete list of all Vedic aspects (drishti) between planets. Includes full (7th) and special aspects (Mars 4th/8th, Jupiter 5th/9th, Saturn 3rd/10th). */
                        aspects: {
                            /**
                             * @description Planet casting the aspect (graha drishti).
                             * @example Mars
                             */
                            aspectingPlanet: string;
                            /**
                             * @description Planet receiving the aspect.
                             * @example Moon
                             */
                            aspectedPlanet: string;
                            /**
                             * @description Vedic aspect type. All planets have 7th aspect. Special aspects: Mars 4th/8th, Jupiter 5th/9th, Saturn 3rd/10th.
                             * @example 7th
                             * @enum {string}
                             */
                            aspectType: "conjunction" | "7th" | "4th" | "8th" | "5th" | "9th" | "3rd" | "10th";
                            /**
                             * @description Aspect strength percentage (0-100). 100 = exact aspect, decreases with orb distance.
                             * @example 100
                             */
                            strength: number;
                            /**
                             * @description Angular distance from exact aspect in degrees. Smaller orb = more potent aspect.
                             * @example 2.5
                             */
                            orb: number;
                        }[];
                        /** @description Aspect table grouped by aspecting planet. useful for rendering aspect grids in astrology software. */
                        aspectTable: {
                            /**
                             * @description Planet casting aspects.
                             * @example Mars
                             */
                            planet: string;
                            /** @description All aspects cast by this planet. */
                            aspects: {
                                /**
                                 * @description Planet being aspected.
                                 * @example Jupiter
                                 */
                                planet: string;
                                /**
                                 * @description Vedic aspect house (7th, 4th, 8th, 5th, 9th, 3rd, 10th, or conjunction).
                                 * @example 8th
                                 */
                                aspectType: string;
                                /**
                                 * @description Aspect strength percentage.
                                 * @example 85
                                 */
                                strength: number;
                            }[];
                        }[];
                        /** @description Pairs of planets aspecting each other simultaneously. Mutual aspects amplify planetary influence significantly. */
                        mutualAspects: {
                            /**
                             * @description First planet in the mutual aspect pair.
                             * @example Mars
                             */
                            planet1: string;
                            /**
                             * @description Second planet in the mutual aspect pair.
                             * @example Saturn
                             */
                            planet2: string;
                            /**
                             * @description The aspect type shared mutually. Mutual aspects are especially strong in Vedic astrology.
                             * @example 7th
                             */
                            aspectType: string;
                        }[];
                    };
                };
            };
        };
    };
