    getNumberMeaning: {
        parameters: {
            query?: {
                /** @description Response language (ISO 639-1). Supported: en, tr, de, es, hi, pt, fr, ru. Defaults to en. Languages without translations yet return English. */
                lang?: "en" | "tr" | "de" | "es" | "hi" | "pt" | "fr" | "ru";
            };
            header?: never;
            path: {
                /** @description Numerology number (1-9, 11, 22, 33) */
                number: string;
            };
            cookie?: never;
        };
        requestBody?: never;
        responses: {
            /** @description Successfully retrieved number meaning */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        /**
                         * @description Requested number
                         * @example 5
                         */
                        number: number;
                        /**
                         * @description Number type
                         * @example single
                         * @enum {string}
                         */
                        type: "single" | "master";
                        meaning: {
                            /**
                             * @description Numerology archetype name. A single phrase capturing the core identity of this number, such as "The Leader" for 1 or "The Master Builder" for 22.
                             * @example The Adventurer
                             */
                            title: string;
                            /**
                             * @description Ten defining personality traits and energetic themes. Useful for personality snapshots, compatibility matching, and building numerology profile summaries.
                             * @example [
                             *       "freedom",
                             *       "adventure",
                             *       "versatile",
                             *       "dynamic",
                             *       "curious"
                             *     ]
                             */
                            keywords: string[];
                            /**
                             * @description Authoritative 300 to 500 word interpretation covering personality, life purpose, and core themes. Written by numerology experts and suitable for full-page readings.
                             * @example In the span of single-digit numbers 1 to 9, 5 is the number in the exact middle...
                             */
                            description: string;
                            /**
                             * @description Core strengths and positive qualities. Each entry pairs a trait name with a detailed explanation of how it manifests in real life.
                             * @example [
                             *       "Curious",
                             *       "Adaptable",
                             *       "Social"
                             *     ]
                             */
                            strengths: string[];
                            /**
                             * @description Growth areas and shadow qualities. Each entry explains the root cause, how it surfaces, and constructive strategies for working through it.
                             * @example [
                             *       "Non-committal",
                             *       "Unreliable",
                             *       "Directionless"
                             *     ]
                             */
                            challenges: string[];
                            /**
                             * @description Tailored career guidance with specific job titles, industries, and work environments. Explains why certain professional paths resonate with this number.
                             * @example Life Path 5 thrives in careers that offer freedom, variety, and constant stimulation...
                             */
                            career: string;
                            /**
                             * @description Love, friendship, and family dynamics. Covers romantic compatibility with other numbers, communication style, and the key relationship lessons.
                             * @example Life Path 5 individuals are exciting, charming, and freedom-loving partners...
                             */
                            relationships: string;
                            /**
                             * @description Spiritual path, soul lessons, and recommended practices. Explores the deeper purpose behind this number and guidance for personal growth.
                             * @example Five is the rebel, the traveler, the agent of change...
                             */
                            spirituality: string;
                        };
                    };
                };
            };
            /** @description Invalid number (must be 1-9, 11, 22, or 33) */
            400: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        /**
                         * @description Validation error when the requested number is not a valid numerology number (1-9, 11, 22, or 33).
                         * @example Invalid numerology number
                         */
                        error: string;
                    };
                };
            };
            /** @description Number meaning not found */
            404: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": {
                        /**
                         * @description Error message when the meaning for the requested number could not be found.
                         * @example Number meaning for 10 not found
                         */
                        error: string;
                    };
                };
            };
        };
    };
